#!/usr/bin/env python3
"""
RedControl v2.1
Advanced display pipeline control for AMD GPUs (DCN)

Per-pipe dithering/truncation via the FMT block, color & depth properties,
and live DisplayPort stream-encoder control — all through UMR + xrandr.
"""

