from pathlib import Path
from tkinter import filedialog, messagebox

# Constants
FMT_INACTIVE_VALUE = "0x00600000"  # Register value indicating FMT is inactive


# ---------------------------------------------------------------------------
# Console logging control (GUI apps should be quiet by default)
#   - Set REDCONTROL_DEBUG=1 or run with --debug to see verbose console output
#   - Set REDCONTROL_QUIET=0 or run with --console to show normal console output
# ---------------------------------------------------------------------------
import builtins as _builtins

APP_NAME = "RedControl"
APP_ID = "redcontrol"
APP_VERSION = "2.1"

# Global app instance for routing warnings/errors into the CMD Log
APP_INSTANCE = None

def _env_flag(name: str, default: bool = False) -> bool:
    v = os.getenv(name)
    if v is None:
        return default
    return str(v).strip().lower() in ("1", "true", "yes", "y", "on")

def _is_debug() -> bool:
    return _env_flag("REDCONTROL_DEBUG", False)

def _is_quiet() -> bool:
    # Default quiet for GUI apps (no console spam)
    return _env_flag("REDCONTROL_QUIET", True)

def console_print(*args, **kwargs):
    """Print to console only when not in quiet mode, or for warnings/errors, or when debug is enabled.

    In quiet mode, warnings/errors are still printed, and also routed into the CMD Log (red ✗) when available.
    """
    try:
        msg = " ".join(str(a) for a in args)
    except Exception:
        msg = ""

    is_problem = any(tok in msg for tok in ("Error", "ERROR", "Warning", "WARNING", "⚠️", "✗", "Failed", "FAILED"))

    # Route problems to the CMD Log if the GUI is up
    try:
        global APP_INSTANCE
        if is_problem and APP_INSTANCE is not None:
            APP_INSTANCE.log_runtime_error_to_cmdlog(msg)
    except Exception:
        pass

    if _is_debug() or (not _is_quiet()):
        return _builtins.print(*args, **kwargs)

    # Quiet mode: only print warnings / errors
    if is_problem:
        return _builtins.print(*args, **kwargs)
    return None


try:
    import tkinter as tk
    from tkinter import ttk, messagebox
except ImportError:
    console_print("Error: tkinter not installed")
    sys.exit(1)

