def _b64_png_to_bytes(b64_str: str) -> bytes:
    return base64.b64decode(b64_str.encode("ascii"))

def _icon_autocrop_rgba(im, pad_frac: float = 0.02):
    """Crop to non-transparent bounds and add a small transparent padding.

    This makes icons look larger/crisper in docks/panels by removing excessive
    empty margins while still keeping a little breathing room.
    """
    try:
        if im is None:
            return None
        im = im.convert("RGBA")
        alpha = im.split()[-1]
        bbox = alpha.getbbox()
        if not bbox:
            return im
        im = im.crop(bbox)
        w, h = im.size
        pad = max(0, int(max(w, h) * pad_frac))
        if pad <= 0:
            return im
        canvas = Image.new("RGBA", (w + 2 * pad, h + 2 * pad), (0, 0, 0, 0))
        canvas.paste(im, (pad, pad), im)
        return canvas
    except Exception:
        return im

def _icon_to_square(im, size: int, pad_frac: float = 0.02):
    """Fit an RGBA image into a size×size square, preserving aspect."""
    try:
        if im is None:
            return None
        im = _icon_autocrop_rgba(im, pad_frac=pad_frac)
        # Use high quality downsampling for tray sizes
        im = im.copy()
        im.thumbnail((size, size), Image.LANCZOS)
        canvas = Image.new("RGBA", (size, size), (0, 0, 0, 0))
        x = (size - im.size[0]) // 2
        y = (size - im.size[1]) // 2
        canvas.paste(im, (x, y), im)
        return canvas
    except Exception:
        return im



def _icon_source_image():
    """Load the embedded source icon as an RGBA PIL Image."""
    if not HAS_PIL:
        return None
    try:
        b = _b64_png_to_bytes(EMBEDDED_ICON_SRC_PNG_B64)
        return Image.open(io.BytesIO(b)).convert("RGBA")
    except Exception:
        return None


def _make_circular_icon(src_im, size: int, *, pad_frac: float = 0.04, sharpen: bool = False,
                        ring_only: bool = False, ring_inner_frac: float = 0.56):
    """Create a circular icon with a black circular background and transparent outside.

    - pad_frac: how much transparent padding to keep (smaller -> icon reads larger)
    - sharpen: apply a light unsharp mask after resizing (helps text clarity)
    - ring_only: cover the center with a black circle to make a textless ring for tray
    - ring_inner_frac: inner cover circle radius as fraction of icon size
    """
    if not HAS_PIL or src_im is None:
        return None
    try:
        # Center-crop to square
        im = src_im
        w, h = im.size
        m = min(w, h)
        left = (w - m) // 2
        top = (h - m) // 2
        im = im.crop((left, top, left + m, top + m))

        # Resize icon into padded square
        inner = max(1, int(size * (1.0 - 2.0 * pad_frac)))
        im = im.resize((inner, inner), Image.LANCZOS)
        if sharpen:
            try:
                im = im.filter(ImageFilter.UnsharpMask(radius=1, percent=(220 if size <= 32 else 160), threshold=2))
            except Exception:
                pass

        # Base canvas (transparent)
        canvas = Image.new("RGBA", (size, size), (0, 0, 0, 0))

        # Black circle background
        bg = Image.new("RGBA", (size, size), (0, 0, 0, 0))
        d = ImageDraw.Draw(bg)
        # Leave 1px margin so anti-aliasing doesn't clip
        d.ellipse((1, 1, size - 2, size - 2), fill=(0, 0, 0, 255), outline=(255, 255, 255, 40))

        # Paste resized art centered
        x = (size - inner) // 2
        y = (size - inner) // 2
        bg.paste(im, (x, y), im)

        if ring_only:
            # Cover center with black to remove text/detail for tray readability.
            # ring_inner_frac is interpreted as a fraction of the OUTER RADIUS (not of `size`).
            cx = cy = size // 2
            outer_r = int((size - 3) / 2)
            r = int(outer_r * float(ring_inner_frac))
            # Clamp so we never cover the outer ring completely
            r = max(0, min(r, outer_r - 1))
            d = ImageDraw.Draw(bg)
            d.ellipse((cx - r, cy - r, cx + r, cy + r), fill=(0, 0, 0, 255))

        # Circular alpha mask for the whole icon (outside transparent)
        mask = Image.new("L", (size, size), 0)
        md = ImageDraw.Draw(mask)
        md.ellipse((1, 1, size - 2, size - 2), fill=255)
        canvas.paste(bg, (0, 0), mask)
        return canvas
    except Exception:
        return None


def set_embedded_tk_icon(root):
    """Set window/taskbar icon using an embedded circular icon."""
    if not HAS_PIL:
        return
    try:
        src = _icon_source_image()
        if src is None:
            return
        sizes = (16, 32, 64, 128)
        imgs = []
        for s in sizes:
            # Less padding for small sizes so it reads bigger in docks.
            pad = 0.045 if s <= 32 else 0.055
            # Sharpen small sizes to keep text crisper
            shp = True if s <= 64 else False
            im = _make_circular_icon(src, s, pad_frac=pad, sharpen=shp, ring_only=False)
            if im is None:
                continue
            buf = io.BytesIO()
            im.save(buf, format="PNG")
            tk_b64 = base64.b64encode(buf.getvalue()).decode("ascii")
            imgs.append(tk.PhotoImage(data=tk_b64))
        if imgs:
            root.iconphoto(True, *imgs)
            root._redcontrol_icon_refs = tuple(imgs)
    except Exception:
        pass


def get_embedded_tray_icon_image(size: int = 24):
    """Return a PIL Image (RGBA) for the tray icon.

    Uses a ring-only variant (no text) with a black circular background.
    """
    if not HAS_PIL:
        return None
    try:
        src = _icon_source_image()
        if src is None:
            return Image.new("RGBA", (size, size), (0, 0, 0, 0))
        # Tray: make it big and simple
        pad = 0.03 if size <= 24 else 0.04
        return _make_circular_icon(src, size, pad_frac=pad, sharpen=True, ring_only=True, ring_inner_frac=0.72)
    except Exception:
        try:
            return Image.new("RGBA", (size, size), (0, 0, 0, 0))
        except Exception:
            return None
class ToolTip:
    """Create tooltip for widgets"""
    _active_tooltips = []  # Track all tooltips globally

    def __init__(self, widget, text):
        self.widget = widget
        self.text = text
        self.tooltip = None
        self.after_id = None
        self.widget.bind("<Enter>", self.schedule_tooltip)
        self.widget.bind("<Leave>", self.hide_tooltip)
        self.widget.bind("<Button>", self.hide_tooltip)  # Hide on click
        self.widget.bind("<FocusOut>", self.hide_tooltip)  # Hide on focus loss
        ToolTip._active_tooltips.append(self)  # Track this tooltip

    def schedule_tooltip(self, event=None):
        """Schedule tooltip to appear after delay"""
        ToolTip.hide_all_tooltips()  # Hide all tooltips first
        self.after_id = self.widget.after(500, self.show_tooltip)  # 500ms delay

    def show_tooltip(self, event=None):
        try:
            # Cancel scheduled tooltip if exists
            if self.after_id:
                self.widget.after_cancel(self.after_id)
                self.after_id = None

            x = self.widget.winfo_rootx() + 25
            y = self.widget.winfo_rooty() + 25

            self.tooltip = tk.Toplevel(self.widget)
            self.tooltip.wm_overrideredirect(True)
            self.tooltip.wm_geometry(f"+{x}+{y}")

            label = tk.Label(self.tooltip, text=self.text,
                            background="#ffffe0", foreground="black",
                            relief=tk.SOLID, borderwidth=1,
                            font=("Arial", 9), padx=10, pady=6,
                            justify=tk.LEFT)
            label.pack()
        except:
            pass

    def hide_tooltip(self, event=None):
        """Hide tooltip and cancel any scheduled showing"""
        if self.after_id:
            self.widget.after_cancel(self.after_id)
            self.after_id = None
        if self.tooltip:
            try:
                self.tooltip.destroy()
            except:
                pass
            self.tooltip = None

    @classmethod
    def hide_all_tooltips(cls):
        """Hide all active tooltips"""
        for tt in cls._active_tooltips:
            if tt and tt.tooltip:
                try:
                    tt.tooltip.destroy()
                except:
                    pass
                tt.tooltip = None
            if tt and tt.after_id:
                try:
                    tt.widget.after_cancel(tt.after_id)
                except:
                    pass
                tt.after_id = None

class ToggleSwitch(tk.Canvas):
    """iOS-style toggle switch"""
    def __init__(self, parent, variable, command=None, **kwargs):
        self.width = 50
        self.height = 24
        super().__init__(parent, width=self.width, height=self.height,
                        highlightthickness=0, **kwargs)

        self.variable = variable
        self.command = command

        # Colors
        self.bg_on = "#4A90E2"  # Blue when ON
        self.bg_off = "#CCCCCC"  # Gray when OFF
        self.knob_color = "#FFFFFF"  # White knob
        self.shadow_color = "#999999"  # Gray shadow (no alpha needed)

        # Draw initial state
        self.draw()

        # Bind click
        self.bind("<Button-1>", self.toggle)

        # Update when variable changes externally
        self.variable.trace_add("write", lambda *args: self.draw())

    def draw(self):
        """Draw the toggle switch"""
        self.delete("all")

        is_on = self.variable.get()
        bg_color = self.bg_on if is_on else self.bg_off
        knob_x = 30 if is_on else 8

        # Draw background (rounded rectangle)
        self.create_oval(0, 0, self.height, self.height, fill=bg_color, outline=bg_color)
        self.create_oval(self.width - self.height, 0, self.width, self.height,
                        fill=bg_color, outline=bg_color)
        self.create_rectangle(self.height // 2, 0, self.width - self.height // 2, self.height,
                            fill=bg_color, outline=bg_color)

        # Draw knob (circle with simple shadow - no alpha)
        # Shadow slightly offset and darker
        shadow_offset = 1
        self.create_oval(knob_x + shadow_offset, 4 + shadow_offset,
                        knob_x + 16 + shadow_offset, 20 + shadow_offset,
                        fill="#AAAAAA", outline="")
        # Main knob on top
        self.create_oval(knob_x, 4, knob_x + 16, 20,
                        fill=self.knob_color, outline="#DDDDDD", width=1)

    def toggle(self, event=None):
        """Toggle the switch"""
        new_value = not self.variable.get()
        self.variable.set(new_value)
        self.draw()
        if self.command:
            self.command()

# AMD GPU codename to Navi mapping
ASIC_TO_NAVI = {
    # RDNA 1
    'navi10': 'Navi 10',
    'navi12': 'Navi 12', 
    'navi14': 'Navi 14',
    
    # RDNA 2
    'navi21': 'Navi 21',
    'navi22': 'Navi 22',
    'navi23': 'Navi 23',
    'navi24': 'Navi 24',
    'dimgrey_cavefish': 'Navi 23',  # RX 6600/6650
    'navy_flounder': 'Navi 22',     # RX 6700
    'sienna_cichlid': 'Navi 21',    # RX 6800/6900
    'beige_goby': 'Navi 24',        # RX 6400/6500
    'yellow_carp': 'Navi 24 APU',   # Rembrandt APU
    
    # RDNA 3
    'navi31': 'Navi 31',
    'navi32': 'Navi 32',
    'navi33': 'Navi 33',
    'plum_bonito': 'Navi 33',       # RX 7600
    'wheat_nas': 'Navi 32',         # RX 7800
    'navi3x': 'Navi 31',            # RX 7900
    
    # APUs
    'vangogh': 'Van Gogh',          # Steam Deck
    'rembrandt': 'Rembrandt',       # Ryzen 6000
    'phoenix': 'Phoenix',           # Ryzen 7040
    'renoir': 'Renoir',             # Ryzen 4000
    'cezanne': 'Cezanne',           # Ryzen 5000
    
    # Older
    'vega10': 'Vega 10',
    'vega20': 'Vega 20',
    'raven': 'Raven Ridge',
    'picasso': 'Picasso',
}

def get_display_name(asic_name):
    """Convert ASIC name to display name"""
    if not asic_name:
        return 'AMD GPU'
    
    asic_lower = asic_name.lower()
    
    # Check direct mapping first
    if asic_lower in ASIC_TO_NAVI:
        return ASIC_TO_NAVI[asic_lower]
    
    # Check if it contains a known name
    for key, value in ASIC_TO_NAVI.items():
        if key in asic_lower:
            return value
    
    # Fallback: format the name nicely
    return asic_name.replace('_', ' ').title()



class RedControl:


    def apply_modern_ttk_styles(self):
        """Apply a more modern look to ttk widgets (Notebook tabs, Comboboxes, Scrollbars)."""
        try:
            import tkinter.ttk as ttk
        except Exception:
            return

        themes = getattr(self, "themes", {}) or {}
        theme_name = getattr(self, "theme_name", "")
        t = themes.get(theme_name) or themes.get("modern_dark") or themes.get("modern_light") or {}

        bg = t.get("bg_content", t.get("bg", "#111"))
        fg = t.get("fg", "#eee")
        muted = t.get("fg_muted", "#bdbdbd")
        accent = t.get("accent", "#4aa3ff")
        btn = t.get("btn", "#2a2a2a")
        btn_alt = t.get("btn_alt", "#333333")
        border = t.get("border", t.get("line", "#3a3a3a"))
        entry_bg = t.get("entry_bg", btn_alt)

        self.ttk_style = ttk.Style()
        try:
            self.ttk_style.theme_use("clam")
        except Exception:
            pass

        # Notebook
        self.ttk_style.configure(
            "Modern.TNotebook",
            background=bg,
            borderwidth=0,
            tabmargins=(0, 8, 0, 0),
        )
        self.ttk_style.configure(
            "Modern.TNotebook.Tab",
            background=btn,
            foreground=muted,
            padding=(14, 9),
            borderwidth=0,
            focuscolor=accent,
        )
        self.ttk_style.map(
            "Modern.TNotebook.Tab",
            background=[("selected", bg), ("active", btn_alt)],
            foreground=[("selected", fg), ("active", fg)],
        )

        # Combobox
        self.ttk_style.configure(
            "Modern.TCombobox",
            fieldbackground=entry_bg,
            background=entry_bg,
            foreground=fg,
            bordercolor=border,
            lightcolor=border,
            darkcolor=border,
            arrowcolor=fg,
            padding=(10, 6),
            relief="flat",
        )
        self.ttk_style.map(
            "Modern.TCombobox",
            fieldbackground=[("readonly", entry_bg), ("disabled", btn)],
            foreground=[("readonly", fg), ("disabled", muted)],
            background=[("readonly", entry_bg), ("active", entry_bg)],
        )

        # Scrollbar
        self.ttk_style.configure(
            "Modern.Vertical.TScrollbar",
            troughcolor=bg,
            background=btn_alt,
            bordercolor=bg,
            lightcolor=btn_alt,
            darkcolor=btn_alt,
            arrowcolor=muted,
        )


    def _short_connector_label(self, c: str) -> str:
        c = (c or "").strip()
        if c.startswith("DisplayPort-"):
            return "DP-" + c.split("-", 1)[1]
        if c.startswith("HDMI-"):
            return "HDMI-" + c.split("-")[-1]
        return c


    # Class constants for bit depth mappings
    TRUNCATE_DEPTH_MAP = {0: "6-bit", 1: "8-bit", 2: "10-bit", 3: "12-bit"}
    TRUNCATE_DEPTH_REVERSE = {"6-bit": 0, "8-bit": 1, "10-bit": 2, "12-bit": 3}
    DITHER_DEPTH_MAP = {0: "6-bit", 1: "8-bit", 2: "10-bit"}
    DITHER_DEPTH_REVERSE = {"6-bit": 0, "8-bit": 1, "10-bit": 2}
    TRUNCATE_MODE_MAP = {0: "Truncate", 1: "Round"}
    TRUNCATE_MODE_REVERSE = {"Truncate": 0, "Round": 1}

    def __init__(self, root):
        self.root = root
        self.root.title("RedControl")
        # Slightly larger default window to avoid UI clipping on some DPI/font combinations.
        # (10% larger than the previous 1638x1148)
        self.root.geometry("1802x1263")
        self.root.minsize(1000, 950)

        # Detect Wayland early
        self.is_wayland = self.detect_wayland()

        # Initialize DRM controller for universal X11/Wayland support
        self.drm = None
        self.drm_available = False
        try:
            # Import DRM controller (same directory)
            import sys
            import importlib.util

            # Try to load drm_controller from same directory as this script
            script_dir = os.path.dirname(os.path.abspath(__file__))
            drm_path = os.path.join(script_dir, 'drm_controller.py')

            if os.path.exists(drm_path):
                spec = importlib.util.spec_from_file_location("drm_controller", drm_path)
                drm_module = importlib.util.module_from_spec(spec)
                spec.loader.exec_module(drm_module)

                # Initialize DRM
                self.drm = drm_module.DRMController()
                if self.drm.initialized:
                    self.drm_available = True
                    # DRM backend available (silent - users don't need to know)
                else:
                    self.drm = None
            else:
                # drm_controller.py not found - this is expected, we don't use it yet
                pass
        except Exception as e:
            self.drm = None

        # Colors - Light mode only
        self.bg = "#F5F5F5"
        self.fg = "#2C2C2C"
        self.accent = "#4A90E2"

        self.gpu_instance = None
        self.asic_name = None
        self.gpu_name = None
        self.block_name = None
        self.active_outputs = {}
        self.initial_values = {}  # Store hardware state at startup
        self.tray_icon = None
        self.tray_failed = False  # Track if tray initialization failed
        self.passwordless_just_enabled = False  # Track if passwordless was just enabled in this session

        # Settings persistence
        self.settings_dir = Path.home() / '.config' / 'redcontrol'
        self.settings_file = self.settings_dir / 'monitor_settings.json'
        self.settings_dir.mkdir(parents=True, exist_ok=True)

        # UI theme (persisted)
        self.theme_name = "modern_dark"
        try:
            ui_cfg = self.settings_dir / "ui.json"
            if ui_cfg.exists():
                data = json.loads(ui_cfg.read_text())
                self.theme_name = data.get("theme", self.theme_name)
        except Exception:
            pass
        self.root.configure(bg=self.bg)

        # Setup close behavior (disable tray when running as root to avoid D-Bus issues)
        if HAS_TRAY and os.geteuid() != 0:
            self.root.protocol("WM_DELETE_WINDOW", self.minimize_to_tray)

        self.create_ui()
        self.auto_detect_gpu()

    def create_tray_icon_image(self):
        """Return the embedded tray icon image (PIL Image, RGBA)."""
        return get_embedded_tray_icon_image(24) or Image.new("RGBA", (24, 24), (0, 0, 0, 0))


    def minimize_to_tray(self):
        """Hide to tray"""
        if HAS_TRAY and self.tray_icon is None:
            self.root.withdraw()
            try:
                image = self.create_tray_icon_image()
                menu = pystray.Menu(
                    pystray.MenuItem('Show Window', self.show_from_tray, default=True),
                    pystray.Menu.SEPARATOR,
                    pystray.MenuItem('Exit', self.exit_app)
                )
                self.tray_icon = pystray.Icon("redcontrol", image, "RedControl", menu)

                # Set up error recovery flag
                self.tray_failed = False

                # Run tray icon in thread - catch DBus errors
                def run_tray():
                    try:
                        self.tray_icon.run()
                    except Exception as e:
                        # Tray initialization failed (usually DBus error with sudo)
                        self.tray_failed = True
                        # Schedule window show from main thread
                        self.root.after(0, lambda: self.recover_from_tray_failure(str(e)))

                # Start tray thread
                tray_thread = threading.Thread(target=run_tray, daemon=True)
                tray_thread.start()

                # Schedule a check to detect if tray failed to start
                def check_tray():
                    if self.tray_failed:
                        # Already handled by thread error
                        return
                    # Check if thread is still alive after initialization period
                    if not tray_thread.is_alive():
                        # Thread died unexpectedly
                        self.recover_from_tray_failure("Tray thread died")

                self.root.after(1500, check_tray)  # Check after 1.5 seconds

            except Exception as e:
                console_print(f"Failed to create tray icon: {e}")
                console_print("Showing window instead")
                self.root.deiconify()
        else:
            self.root.destroy()

    def recover_from_tray_failure(self, error_msg):
        """Recover from tray initialization failure by showing window"""
        console_print(f"⚠️ System tray failed: {error_msg}")
        console_print("⚠️ This is a known issue when running with 'sudo' - DBus permissions")
        console_print("ℹ️  Showing window instead...")
        self.root.deiconify()
        self.tray_icon = None

    def tray_disable_all(self):
        """Disable all from tray - thread-safe"""
        self.root.after(0, self._do_tray_disable_all)

    def _do_tray_disable_all(self):
        """Actually disable all (on main thread)"""
        for name, info in self.active_outputs.items():
            self.disable_all(info['index'])

    def tray_enable_default(self):
        """Enable default from tray - thread-safe"""
        self.root.after(0, self._do_tray_enable_default)

    def _do_tray_enable_default(self):
        """Actually enable default (on main thread)"""
        for name, info in self.active_outputs.items():
            self.enable_default(info['index'])

    def tray_refresh(self):
        """Refresh from tray - thread-safe"""
        self.root.after(0, self._do_tray_refresh)

    def _do_tray_refresh(self):
        """Actually refresh (on main thread)"""
        self.scan_monitors()

    def show_from_tray(self):
        """Show from tray - thread-safe"""
        self.root.after(0, self._do_show_from_tray)

    def _do_show_from_tray(self):
        """Actually show window (on main thread)"""
        self.root.deiconify()
        if self.tray_icon:
            self.tray_icon.stop()
            self.tray_icon = None


    def exit_app(self, *args, **kwargs):
        """Exit the application (safe to call from tray thread or UI)."""
        def _do():
            # Stop tray icon if present
            try:
                if getattr(self, 'tray_icon', None):
                    try:
                        self.tray_icon.stop()
                    except Exception:
                        pass
                    self.tray_icon = None
            except Exception:
                pass

            # Quit + destroy Tk
            try:
                self.root.quit()
            except Exception:
                pass
            try:
                self.root.destroy()
            except Exception:
                # Last-resort hard exit if Tk is in a bad state
                try:
                    import os
                    os._exit(0)
                except Exception:
                    pass

        # If called from tray thread, schedule onto Tk main thread
        try:
            self.root.after(0, _do)
        except Exception:
            _do()


    def rebuild_ui(self):

        """Rebuild the entire UI in-place to apply a new theme without restarting the process.

        Notes:
        - Preserves window size + position so theme toggles don't jump to top-left.
        - Hides the window during rebuild to avoid top-bar reflow flicker.
        """
        prev_geom = None
        prev_xywh = None  # (w, h, x, y)
        used_alpha_hide = False
        used_withdraw_hide = False

        try:
            active = getattr(self, "active_section", "DITH")
            gpu_selected = None
            try:
                gpu_selected = self.gpu_selector_var.get()
            except Exception:
                pass

            # Capture current window geometry/position as robustly as possible
            try:
                self.root.update_idletasks()
                prev_geom = self.root.wm_geometry()
                w = int(self.root.winfo_width())
                h = int(self.root.winfo_height())
                x = int(self.root.winfo_x())
                y = int(self.root.winfo_y())
                # winfo_* can be 1/0 very early; fall back to parsing geometry string
                if w <= 1 or h <= 1 or x < 0 or y < 0:
                    mg = re.match(r"(\d+)x(\d+)\+(-?\d+)\+(-?\d+)", prev_geom or "")
                    if mg:
                        w, h, x, y = map(int, mg.groups())
                prev_xywh = (w, h, x, y)
            except Exception:
                prev_xywh = None

            # Hide during rebuild to prevent any visible layout thrash
            try:
                self.root.wm_attributes("-alpha", 0.0)
                used_alpha_hide = True
            except Exception:
                try:
                    self.root.withdraw()
                    used_withdraw_hide = True
                except Exception:
                    pass

            # Tear down old widgets
            for child in list(self.root.winfo_children()):
                try:
                    child.destroy()
                except Exception:
                    pass

            # Rebuild widgets
            self.create_ui()

            # Best-effort restore state (active section + GPU selection)
            try:
                self.set_active_section(active)
            except Exception:
                pass
            if gpu_selected:
                try:
                    vals = []
                    try:
                        vals = list(getattr(self.gpu_selector, "cget")("values"))
                    except Exception:
                        pass
                    if not vals or gpu_selected in vals:
                        self.gpu_selector_var.set(gpu_selected)
                        self.switch_gpu()
                except Exception:
                    pass

            # Repopulate GPU + monitor UI after rebuild
            try:
                self.root.after(50, self.auto_detect_gpu)
            except Exception:
                pass

            # Restore exact size + position BEFORE showing (critical on some WMs)
            try:
                self.root.update_idletasks()
                if prev_xywh:
                    w, h, x, y = prev_xywh
                    self.root.geometry(f"{w}x{h}+{x}+{y}")
                elif prev_geom:
                    self.root.geometry(prev_geom)
                self.root.update_idletasks()
            except Exception:
                pass

            # Show again
            try:
                if used_withdraw_hide:
                    self.root.deiconify()
                if used_alpha_hide:
                    self.root.wm_attributes("-alpha", 1.0)
            except Exception:
                try:
                    self.root.deiconify()
                except Exception:
                    pass

            # Keep it in the same spot and prevent any "jump" feelings
            try:
                self.root.lift()
                self.root.focus_force()
            except Exception:
                pass

        except Exception as e:
            # Ensure the window is visible again if we failed mid-rebuild
            try:
                if used_withdraw_hide:
                    self.root.deiconify()
                self.root.wm_attributes("-alpha", 1.0)
            except Exception:
                try:
                    self.root.deiconify()
                except Exception:
                    pass
            try:
                messagebox.showerror("Theme", f"Couldn't apply theme live: {e}")
            except Exception:
                pass



    
    
    def create_ui(self):
        """Create UI (modern shell + original controls)."""
        # ---------------------------
        # Theme (default: eink-friendly light)
        # ---------------------------
        # If these were already set elsewhere, keep them; otherwise set defaults.
        if not hasattr(self, "theme_name"):
            self.theme_name = "modern_dark"  # default theme

        THEMES = {
            "modern_dark": {
                "bg_app": "#0d1117",
                "bg_sidebar": "#161b22",
                "bg_content": "#0d1117",
                "bg_card": "#161b22",
                "bg_input": "#21262d",
                "border": "#30363d",
                "fg": "#e6edf3",
                "fg_muted": "#8b949e",
                "accent": "#58a6ff",
                "btn": "#21262d",
                "btn_fg": "#e6edf3",
                "btn_alt": "#30363d",
            },
            "eink": {
                "bg_app": "#ffffff",
                "bg_sidebar": "#ffffff",
                "bg_content": "#ffffff",
                "bg_card": "#ffffff",
                "bg_input": "#ffffff",
                "border": "#000000",
                "fg": "#000000",
                "fg_muted": "#333333",
                "accent": "#000000",
                "btn": "#000000",
                "btn_fg": "#ffffff",
                "btn_alt": "#f0f0f0",
            },
        }
        # Copy so we can safely add derived defaults without mutating the THEMES dict
