        def _make_section_btn(key, text_label, icon=""):
            # Button row container with left accent indicator + optional icon
            row = tk.Frame(self.sidebar, bg=t["bg_sidebar"])
            row.pack(fill="x", padx=10, pady=3)

            # Vertical selection indicator (kept)
