            ind.pack(side="left", fill="y")
            self.section_indicators[key] = ind

            # Icon (fixed width so labels align nicely)
            if icon:
                icon_lbl = tk.Label(row, text=icon, bg=t["bg_sidebar"], fg=t["fg_muted"],
                                    font=("Arial", 12, "bold"), width=2, anchor="center")
                icon_lbl.pack(side="left", padx=(8, 0))
            else:
                icon_lbl = None

            btn = tk.Button(
                row,
                text=text_label,
                command=lambda k=key: self.set_active_section(k),
                bg=t["bg_sidebar"], fg=t["fg"],
                activebackground=t["bg_panel"], activeforeground=t["fg"],
                font=("Arial", 11, "bold"),
                anchor="w", padx=12, pady=11,
                relief=tk.FLAT, bd=0, highlightthickness=0
            )
            btn.pack(side="left", fill="x", expand=True, padx=(6 if icon else 8, 0))

            # Make the whole row feel clickable (icon/row clicks activate too)
            def _activate(_e=None):
                self.set_active_section(key)

            row.bind("<Button-1>", _activate)
            if icon_lbl:
                icon_lbl.bind("<Button-1>", _activate)

            # Hover effects (subtle)
            def _enter(_e):
                if getattr(self, "active_section", "DITH") != key:
                    row.configure(bg=t["bg_panel"])
                    btn.configure(bg=t["bg_panel"])
                    if icon_lbl:
                        icon_lbl.configure(bg=t["bg_panel"])
            def _leave(_e):
                if getattr(self, "active_section", "DITH") != key:
                    row.configure(bg=t["bg_sidebar"])
                    btn.configure(bg=t["bg_sidebar"])
                    if icon_lbl:
                        icon_lbl.configure(bg=t["bg_sidebar"])
            row.bind("<Enter>", _enter)
            row.bind("<Leave>", _leave)
            btn.bind("<Enter>", _enter)
            btn.bind("<Leave>", _leave)
            if icon_lbl:
                icon_lbl.bind("<Enter>", _enter)
                icon_lbl.bind("<Leave>", _leave)

            self.section_buttons[key] = (row, btn, icon_lbl)

