    def get_current_output_idx(self):
        """Return the current output idx (the FMT/pipe index used by registers/UI dicts)."""
        try:
            tab_id = self.notebook.select()
            if tab_id and hasattr(self, "tab_id_to_output_idx") and tab_id in self.tab_id_to_output_idx:
                return self.tab_id_to_output_idx[tab_id]
        except Exception:
            pass

        # Fallback: if mapping is missing, attempt to use notebook position.
        try:
            return int(self.notebook.index("current"))
        except Exception:
            return None

    def show_preset_menu(self):
        """Show dropdown menu with preset options."""
        if not hasattr(self, "preset_btn"):
            return

        menu = tk.Menu(self.root, tearoff=0)
        menu.add_command(label="6-bit no dithering", command=lambda: self.apply_static_bpc_preset(0))
        menu.add_command(label="8-bit no dithering", command=lambda: self.apply_static_bpc_preset(1))
        menu.add_command(label="10-bit no dithering", command=lambda: self.apply_static_bpc_preset(2))
        menu.add_command(label="12-bit no dithering", command=lambda: self.apply_static_bpc_preset(3))

        x = self.preset_btn.winfo_rootx()
        y = self.preset_btn.winfo_rooty() + self.preset_btn.winfo_height()
        menu.tk_popup(x, y, 0)




    def reset_all_to_defaults(self):
        """Reset all outputs back to the app-start hardware snapshot (best effort)."""
        active_outputs = getattr(self, "active_outputs", {})
        idxs = []
        try:
            if isinstance(active_outputs, dict):
                for _name, info in active_outputs.items():
                    if isinstance(info, dict) and "index" in info:
                        idxs.append(int(info["index"]))
                    elif isinstance(info, int):
                        idxs.append(info)
                    elif isinstance(info, str) and info.isdigit():
                        idxs.append(int(info))
        except Exception:
            pass

        # Fallback: if we couldn't discover outputs, try common FMT indices.
        if not idxs:
            idxs = list(range(0, 5))

        ok = 0
        for idx in sorted(set(idxs)):
            try:
                self.enable_default_for_output(idx)
                ok += 1
            except Exception as e:
                self.log_debug(f"Failed to reset output {idx}: {e}")

        # Refresh UI state from hardware after resets (best effort)
        try:
            for idx in sorted(set(idxs)):
                self.sync_fmt_ui_from_hw(idx)
        except Exception:
            pass

        self.show_status(f"Reset defaults for {ok} output(s).", "success")

    def sync_fmt_ui_from_hw(self, idx):
        """Sync the FMT dithering/truncate UI controls for an idx from hardware."""
        try:
            reg = f"{self.asic_name}.{self.block_name}.mmFMT{idx}_FMT_BIT_DEPTH_CONTROL"
            out = self.run_umr_command(["-i", str(self.gpu_instance), "-O", "bits", "-r", reg])
            if not out:
                return

            def _get(field):
                m = re.search(rf"{re.escape(field)}\b.*?==\s*(0x[0-9a-fA-F]+|\d+)", out)
                try:
                    return int(m.group(1), 0) if m else None
                except Exception:
                    return None

            # Checkboxes / toggles
            if idx in self.spatial_vars:
                v = _get("FMT_SPATIAL_DITHER_EN")
                if v is not None:
                    self.spatial_vars[idx].set(int(v))
            if idx in self.temporal_vars:
                v = _get("FMT_TEMPORAL_DITHER_EN")
                if v is not None:
                    self.temporal_vars[idx].set(int(v))
            if idx in self.frame_random_vars:
                v = _get("FMT_FRAME_RANDOM_ENABLE")
                if v is not None:
                    self.frame_random_vars[idx].set(int(v))
            if idx in self.rgb_random_vars:
                v = _get("FMT_RGB_RANDOM_ENABLE")
                if v is not None:
                    self.rgb_random_vars[idx].set(int(v))
            if idx in self.highpass_random_vars:
                v = _get("FMT_HIGHPASS_RANDOM_ENABLE")
                if v is not None:
                    self.highpass_random_vars[idx].set(int(v))
            if idx in self.truncate_vars:
                v = _get("FMT_TRUNCATE_EN")
                if v is not None:
                    self.truncate_vars[idx].set(int(v))

            # Dropdowns
            v = _get("FMT_SPATIAL_DITHER_DEPTH")
            if v is not None and idx in self.spatial_depth_vars:
                self.spatial_depth_vars[idx].set(self.DITHER_DEPTH_MAP.get(int(v), "8-bit"))

            v = _get("FMT_TRUNCATE_DEPTH")
            if v is not None and idx in self.truncate_depth_vars:
                self.truncate_depth_vars[idx].set(self.TRUNCATE_DEPTH_MAP.get(int(v), "8-bit"))

            v = _get("FMT_TRUNCATE_MODE")
            if v is not None and idx in self.truncate_mode_vars:
                self.truncate_mode_vars[idx].set(self.TRUNCATE_MODE_MAP.get(int(v), "Truncate"))
        except Exception:
            # Best-effort sync only
            return


    def show_status(self, msg: str, kind: str = "info"):
        """Unified status reporting (bottom status bar + cmdlog fallback)."""
        try:
            if hasattr(self, "status_var") and self.status_var is not None:
                self.status_var.set(msg)
        except Exception:
            pass
        # Also mirror errors/warnings into the cmdlog for visibility
        try:
            if kind in ("error", "warn", "warning") and hasattr(self, "log_runtime_error_to_cmdlog"):
                self.log_runtime_error_to_cmdlog(msg)
        except Exception:
            pass

    def log_debug(self, msg: str):
        """Best-effort debug logging."""
        try:
            if hasattr(self, "log_runtime_error_to_cmdlog"):
                self.log_runtime_error_to_cmdlog(f"[debug] {msg}")
            else:
                print(f"[debug] {msg}")
        except Exception:
            pass

    def enable_default_for_output(self, idx: int):
        """Compatibility wrapper for older preset/reset code paths."""
        try:
            if hasattr(self, "enable_default"):
                return self.enable_default(idx)
        except Exception as e:
            self.log_debug(f"enable_default_for_output failed: {e}")
        return None

    def apply_static_bpc_preset(self, depth_enum):
        """Apply a static no-dither preset (6/8/10/12-bit) to the current output."""
        idx = self.get_current_output_idx()
        if idx is None:
            self.show_status("No active monitor selected", "warning")
            return

        label = {0:"6-bit",1:"8-bit",2:"10-bit",3:"12-bit"}.get(int(depth_enum), "8-bit")

        # Disable all dithering + random
        for var_dict, field in [
            (getattr(self, "spatial_vars", {}), "FMT_SPATIAL_DITHER_EN"),
            (getattr(self, "temporal_vars", {}), "FMT_TEMPORAL_DITHER_EN"),
            (getattr(self, "frame_random_vars", {}), "FMT_FRAME_RANDOM_ENABLE"),
            (getattr(self, "rgb_random_vars", {}), "FMT_RGB_RANDOM_ENABLE"),
            (getattr(self, "highpass_random_vars", {}), "FMT_HIGHPASS_RANDOM_ENABLE"),
        ]:
            if idx in var_dict:
                var_dict[idx].set(0)
                self.toggle_setting(idx, field, var_dict[idx])

        # Truncation on (plain truncate), depth to target
        if idx in self.truncate_vars:
            self.truncate_vars[idx].set(1)
            self.toggle_setting(idx, "FMT_TRUNCATE_EN", self.truncate_vars[idx])

        if idx in self.truncate_mode_vars:
            self.truncate_mode_vars[idx].set("Truncate")
            self.set_truncate_mode(idx)

        if idx in self.truncate_depth_vars:
            self.truncate_depth_vars[idx].set(label)
            self.set_truncate_depth(idx)

        # Keep spatial depth consistent (even though dithering is off)
        if idx in self.spatial_depth_vars:
            self.spatial_depth_vars[idx].set(label)
            self.set_spatial_depth(idx)

        self.show_status(f"Applied {label} static preset (no dithering)", "success")


    def get_drm_connectors(self):
        """Get list of DRM connectors with xrandr, including CRTC mapping"""
        try:
            # Try verbose mode first to get CRTC numbers
            result = subprocess.run(['xrandr', '--verbose'],
                                  capture_output=True, text=True, timeout=5)

            # Fall back to regular mode if verbose fails
            if result.returncode != 0:
                result = subprocess.run(['xrandr', '--query'],
                                      capture_output=True, text=True, timeout=5)

            if result.returncode != 0:
                return {}

            connectors = {}
            current_connector = None

            for line in result.stdout.split('\n'):
                # Match connector lines like "DisplayPort-0 connected primary 3200x1800..."
                conn_match = re.match(r'^([A-Za-z0-9\-]+)\s+(connected|disconnected)', line)
                if conn_match:
                    connector_name = conn_match.group(1)
                    is_connected = conn_match.group(2) == 'connected'
                    current_connector = connector_name

                    # Extract resolution if connected
                    resolution = None
                    if is_connected:
                        res_match = re.search(r'(\d+)x(\d+)\+', line)
                        if res_match:
                            resolution = f"{res_match.group(1)}x{res_match.group(2)}"

                    connectors[connector_name] = {
                        'connected': is_connected,
                        'resolution': resolution,
                        'crtc': None  # Will be filled in if found
                    }

                # Look for CRTC in verbose output (indented lines after connector)
                elif current_connector and 'CRTC:' in line:
                    crtc_match = re.search(r'CRTC:\s*(\d+)', line)
                    if crtc_match and current_connector in connectors:
                        connectors[current_connector]['crtc'] = int(crtc_match.group(1))
                        console_print(f"DEBUG: {current_connector} → CRTC {crtc_match.group(1)}")

            return connectors
        except Exception as e:
            console_print(f"DEBUG: get_drm_connectors error: {e}")
            return {}

    def get_connector_max_bpc(self, connector_name):
        """Get current max bpc value for a connector (runs as current user)"""
        try:
            # Use xrandr --props to get all properties
            # Note: --output with --props doesn't work on all systems
            result = subprocess.run(['xrandr', '--props'],
                                  capture_output=True, text=True, timeout=5)
            if result.returncode != 0:
                return None

            # Parse output to find the connector and its max bpc
            lines = result.stdout.split('\n')
            found_connector = False

            for i, line in enumerate(lines):
                # Check if this is our connector line
                if line.startswith(connector_name + ' '):
                    found_connector = True
                    # Look at the next ~60 lines for max bpc property
                    # (EDID data can be very long, so we need to search further)
                    for j in range(i+1, min(i+60, len(lines))):
                        prop_line = lines[j]
                        # Properties are indented with tabs/spaces
                        # Stop when we hit another connector (non-indented line starting with a letter)
                        if prop_line and not prop_line[0].isspace() and prop_line[0].isalpha():
                            break

                        # Look for max bpc (with flexible whitespace)
                        if 'max bpc:' in prop_line:
                            match = re.search(r'max bpc:\s*(\d+)', prop_line)
                            if match:
                                return int(match.group(1))
                    break

            return None
        except Exception as e:
            return None

    def set_connector_max_bpc(self, connector_name, bpc_value):
        """Set max bpc for a connector using DRM (universal) or xrandr (X11 only)"""
        try:
            # Get current value for logging
            before_bpc = self.get_connector_max_bpc(connector_name)
            before_value = str(before_bpc) if before_bpc else "Unknown"

            # Try DRM first (works on X11 and Wayland)
            if self.drm_available and self.drm:
                console_print(f"Using DRM to set max bpc on {connector_name}...")
                success = self.drm.set_max_bpc(connector_name, bpc_value)

                if success:
                    self.log_command(f"{connector_name}: Max BPC", before_value,
                                   f"DRM: max bpc = {bpc_value}", str(bpc_value), success=True)
                    return True
                else:
                    console_print(f"  DRM failed, trying xrandr fallback...")

            # Fallback to xrandr (X11 only)
            if not self.is_wayland:
                command = f"xrandr --output {connector_name} --set \"max bpc\" {bpc_value}"

                result = subprocess.run(['xrandr', '--output', connector_name,
                                       '--set', 'max bpc', str(bpc_value)],
                                      capture_output=True, text=True, timeout=5)

                success = result.returncode == 0

                if success:
                    self.log_command(f"{connector_name}: Max BPC", before_value, command, str(bpc_value), success=True)
                else:
                    error = result.stderr[:50] if result.stderr else "Unknown error"
                    self.log_command(f"{connector_name}: Max BPC", before_value, command, f"Error: {error}", success=False)

                return success
            else:
                # On Wayland without DRM
                self.log_command(f"{connector_name}: Max BPC", before_value, "Wayland (no DRM)", "Not available", success=False)
                return False

        except Exception as e:
            self.log_command(f"{connector_name}: Max BPC", "Unknown", "max bpc", f"Exception: {str(e)[:50]}", success=False)
            return False

    def get_current_colorspace_from_debugfs(self, connector_name, monitor_index=None):
        """Read actual colorspace from debugfs for a specific connector

        Args:
            connector_name: e.g. "DisplayPort-0"
            monitor_index: The FMT index (0 for FMT0, 1 for FMT1, etc.)
        """
        import sys
        console_print(f"\n=== get_current_colorspace_from_debugfs CALLED ===", flush=True)
        sys.stdout.flush()
        console_print(f"connector_name={connector_name}, monitor_index={monitor_index}", flush=True)
        sys.stdout.flush()

        try:
            # If we have a monitor index, try that CRTC first
            # FMT0 usually maps to crtc-0, FMT1 to crtc-1, etc.
            if monitor_index is not None:
                # Use sudo find since regular user can't see /sys/kernel/debug/dri
                console_print(f"Looking for colorspace file for crtc-{monitor_index}...")

                # Use find with sudo to locate the file
                try:
                    find_result = subprocess.run(
                        ['sudo', '-n', 'find', '/sys/kernel/debug/dri', '-type', 'f',
                         '-name', 'amdgpu_current_colorspace', '-path', f'*/crtc-{monitor_index}/*'],
                        capture_output=True, text=True, timeout=2
                    )

                    if find_result.returncode == 0 and find_result.stdout.strip():
                        crtc_paths = [p.strip() for p in find_result.stdout.strip().split('\n') if p.strip()]
                        console_print(f"  sudo find found paths: {crtc_paths}")
                    else:
                        console_print(f"  sudo find returned nothing (rc={find_result.returncode})")
                        crtc_paths = []
                except Exception as e:
                    console_print(f"  Exception during sudo find: {e}")
                    crtc_paths = []

                for path in crtc_paths:
                    console_print(f"Trying to read: {path}")
                    try:
                        # Try direct read first
                        with open(path, 'r') as f:
                            colorspace = f.read().strip()
                            if colorspace and colorspace != "":
                                console_print(f"✓ Found colorspace for {connector_name} (FMT{monitor_index}/crtc-{monitor_index}): {colorspace}")
                                return colorspace
                    except PermissionError:
                        # Try with sudo if direct read fails
                        console_print(f"  Direct read failed (permission denied), trying sudo...")
                        try:
                            # First try passwordless sudo
                            result = subprocess.run(['sudo', '-n', 'cat', path],
                                                  capture_output=True, text=True, timeout=1)
                            if result.returncode == 0 and result.stdout.strip():
                                colorspace = result.stdout.strip()
                                console_print(f"Found colorspace for {connector_name} (FMT{monitor_index}/crtc-{monitor_index}): {colorspace}")
                                return colorspace
                            else:
                                # Passwordless failed, try regular sudo (will prompt in terminal)
                                console_print(f"  Passwordless not enabled, trying regular sudo...")
                                console_print(f"  >>> Password prompt will appear in your TERMINAL window! <<<")
                                # Let stdin go to terminal so password prompt works, but suppress stderr to avoid noise
                                result2 = subprocess.Popen(['sudo', 'cat', path],
                                                         stdout=subprocess.PIPE,
                                                         stderr=subprocess.DEVNULL,  # Suppress stderr errors
                                                         stdin=None,
                                                         text=True)
                                stdout, _ = result2.communicate(timeout=30)
                                # Check returncode AFTER communicate()
                                if stdout and stdout.strip():
                                    colorspace = stdout.strip()
                                    console_print(f"Found colorspace for {connector_name} (FMT{monitor_index}/crtc-{monitor_index}): {colorspace}")
                                    return colorspace
                                else:
                                    console_print(f"  sudo cat returned empty or failed: returncode={result2.returncode}")
                        except Exception as e:
                            console_print(f"  Exception during sudo: {e}")
                            pass
                    except:
                        continue

            # Fallback: Try connector mapping
            connector_mapping = {
                'DisplayPort-0': 'DP-1',
                'DisplayPort-1': 'DP-2',
                'DisplayPort-2': 'DP-3',
                'HDMI-A-0': 'HDMI-A-1',
                'HDMI-A-1': 'HDMI-A-2',
            }

            drm_connector = connector_mapping.get(connector_name)

            if drm_connector:
                # Try to find CRTC for this specific connector via sysfs
                card_pattern = f"/sys/class/drm/card*-{drm_connector}"
                matching_paths = glob.glob(card_pattern)

                for card_path in matching_paths:
                    try:
                        status_file = f"{card_path}/status"
                        if os.path.exists(status_file):
                            with open(status_file, 'r') as f:
                                status = f.read().strip()
                                if status == "connected":
                                    # Try common CRTC paths
                                    for crtc_num in range(6):
                                        debugfs_path = f"/sys/kernel/debug/dri/*/crtc-{crtc_num}/amdgpu_current_colorspace"
                                        crtc_paths = glob.glob(debugfs_path)
                                        for crtc_path in crtc_paths:
                                            try:
                                                # Try direct read first
                                                with open(crtc_path, 'r') as f:
                                                    colorspace = f.read().strip()
                                                    if colorspace and colorspace != "":
                                                        console_print(f"Found colorspace for {connector_name}: {colorspace} at {crtc_path}")
                                                        return colorspace
                                            except PermissionError:
                                                # Try with sudo if direct read fails
                                                try:
                                                    # First try passwordless sudo
                                                    result = subprocess.run(['sudo', '-n', 'cat', crtc_path],
                                                                          capture_output=True, text=True, timeout=1)
                                                    if result.returncode == 0 and result.stdout.strip():
                                                        colorspace = result.stdout.strip()
                                                        console_print(f"Found colorspace for {connector_name}: {colorspace} at {crtc_path}")
                                                        return colorspace
                                                    else:
                                                        # Passwordless failed, try regular sudo
                                                        result2 = subprocess.Popen(['sudo', 'cat', crtc_path],
                                                                                 stdout=subprocess.PIPE,
                                                                                 stderr=subprocess.DEVNULL,
                                                                                 stdin=None,
                                                                                 text=True)
                                                        stdout, _ = result2.communicate(timeout=30)
                                                        if stdout and stdout.strip():
                                                            colorspace = stdout.strip()
                                                            console_print(f"Found colorspace for {connector_name}: {colorspace} at {crtc_path}")
                                                            return colorspace
                                                except:
                                                    pass
                                            except:
                                                continue
                    except:
                        continue

            # Final fallback: Scan all available colorspace files
            pattern = "/sys/kernel/debug/dri/*/crtc-*/amdgpu_current_colorspace"

            for path in glob.glob(pattern):
                try:
                    # Try direct read first
                    with open(path, 'r') as f:
                        colorspace = f.read().strip()
                        if colorspace and colorspace != "":
                            console_print(f"Found colorspace (fallback): {colorspace} at {path}")
                            return colorspace
                except PermissionError:
                    # Try with sudo if direct read fails
                    try:
                        # First try passwordless sudo
                        result = subprocess.run(['sudo', '-n', 'cat', path],
                                              capture_output=True, text=True, timeout=1)
                        if result.returncode == 0 and result.stdout.strip():
                            colorspace = result.stdout.strip()
                            console_print(f"Found colorspace (fallback): {colorspace} at {path}")
                            return colorspace
                        else:
                            # Passwordless failed, try regular sudo
                            result2 = subprocess.Popen(['sudo', 'cat', path],
                                                     stdout=subprocess.PIPE,
                                                     stderr=subprocess.DEVNULL,
                                                     stdin=None,
                                                     text=True)
                            stdout, _ = result2.communicate(timeout=30)
                            if stdout and stdout.strip():
                                colorspace = stdout.strip()
                                console_print(f"Found colorspace (fallback): {colorspace} at {path}")
                                return colorspace
                    except:
                        pass
                except (FileNotFoundError, OSError):
                    continue

            return None

        except Exception as e:
            console_print(f"Error reading colorspace from debugfs: {e}")
            return None

            # Fallback: Try connector mapping
            connector_mapping = {
                'DisplayPort-0': 'DP-1',
                'DisplayPort-1': 'DP-2',
                'DisplayPort-2': 'DP-3',
                'HDMI-A-0': 'HDMI-A-1',
                'HDMI-A-1': 'HDMI-A-2',
            }

            drm_connector = connector_mapping.get(connector_name)

            if drm_connector:
                # Try to find CRTC for this specific connector via sysfs
                card_pattern = f"/sys/class/drm/card*-{drm_connector}"
                matching_paths = glob.glob(card_pattern)

                for card_path in matching_paths:
                    try:
                        status_file = f"{card_path}/status"
                        if os.path.exists(status_file):
                            with open(status_file, 'r') as f:
                                status = f.read().strip()
                                if status == "connected":
                                    # Try common CRTC paths
                                    for crtc_num in range(6):
                                        debugfs_path = f"/sys/kernel/debug/dri/*/crtc-{crtc_num}/amdgpu_current_colorspace"
                                        crtc_paths = glob.glob(debugfs_path)
                                        for crtc_path in crtc_paths:
                                            try:
                                                # Try reading directly first
                                                try:
                                                    with open(crtc_path, 'r') as f:
                                                        colorspace = f.read().strip()
                                                        if colorspace and colorspace != "":
                                                            console_print(f"Found colorspace for {connector_name}: {colorspace} at {crtc_path}")
                                                            return colorspace
                                                except PermissionError:
                                                    # Try with sudo -n (only works if passwordless enabled)
                                                    result = subprocess.run(['sudo', '-n', 'cat', crtc_path],
                                                                          capture_output=True, text=True, timeout=0.5)
                                                    if result.returncode == 0:
                                                        colorspace = result.stdout.strip()
                                                        if colorspace and colorspace != "":
                                                            console_print(f"Found colorspace for {connector_name}: {colorspace} at {crtc_path}")
                                                            return colorspace
                                            except:
                                                continue
                    except:
                        continue

            # Final fallback: Scan all available colorspace files
            pattern = "/sys/kernel/debug/dri/*/crtc-*/amdgpu_current_colorspace"

            for path in glob.glob(pattern):
                try:
                    # Try reading directly first
                    try:
                        with open(path, 'r') as f:
                            colorspace = f.read().strip()
                            if colorspace and colorspace != "":
                                console_print(f"Found colorspace (fallback): {colorspace} at {path}")
                                return colorspace
                    except PermissionError:
                        # Try with sudo -n (only works if passwordless enabled)
                        result = subprocess.run(['sudo', '-n', 'cat', path],
                                              capture_output=True, text=True, timeout=0.5)
                        if result.returncode == 0:
                            colorspace = result.stdout.strip()
                            if colorspace and colorspace != "":
                                console_print(f"Found colorspace (fallback): {colorspace} at {path}")
                                return colorspace
                except (subprocess.TimeoutExpired, OSError) as e:
                    console_print(f"  Exception in fallback: {e}")
                    continue

            console_print("=== All methods failed, returning None ===")
            console_print("TROUBLESHOOTING:")
            console_print("1. Check if passwordless is enabled: sudo -k && sudo -n /usr/bin/true")
            console_print("2. Check if cat is in sudoers: sudo cat /etc/sudoers.d/umr-passwordless | grep cat")
            console_print("3. Test sudo cat: sudo -n cat /sys/kernel/debug/dri/0/crtc-0/amdgpu_current_colorspace")
            return None

        except Exception as e:
            console_print(f"=== EXCEPTION in get_current_colorspace_from_debugfs: {e} ===")
            import traceback
            traceback.print_exc()
            return None

    def get_current_broadcast_rgb(self, connector_name):
        """Read current Broadcast RGB value from xrandr"""
        try:
            # Use xrandr --props (NOT --output X --props, that doesn't work on some systems)
            result = subprocess.run(['xrandr', '--props'],
                                  capture_output=True, text=True, timeout=5)
            if result.returncode != 0:
                return None

            lines = result.stdout.split('\n')
            found_connector = False

            for i, line in enumerate(lines):
                # Check if this is our connector line
                if line.startswith(connector_name + ' '):
                    found_connector = True
                    # Look at the next ~60 lines for Broadcast RGB property
                    for j in range(i+1, min(i+60, len(lines))):
                        prop_line = lines[j]
                        # Stop when we hit another connector
                        if prop_line and not prop_line[0].isspace() and prop_line[0].isalpha():
                            break

                        # Look for Broadcast RGB
                        if 'Broadcast RGB:' in prop_line:
                            # Extract value after colon
                            match = re.search(r'Broadcast RGB:\s*(.+)', prop_line)
                            if match:
                                value = match.group(1).strip()
                                console_print(f"Found Broadcast RGB: {value}")
                                return value
                    break

            return None

        except Exception as e:
            console_print(f"Error reading Broadcast RGB: {e}")
            return None

