    def get_monitor_id(self, connector_name):
        """Return the settings key for a monitor.

        Public build: use the connector name as the identity to avoid
        mismatches between X11 connector naming (e.g. DisplayPort-0) and
        DRM sysfs connector naming (e.g. DP-1).
        """
        return connector_name

    def get_monitor_name(self, connector_name):
        """Extract monitor name from EDID with manufacturer + product fallback"""
        try:
            result = subprocess.run(['xrandr', '--props'],
                                  capture_output=True, text=True, timeout=5)
            lines = result.stdout.split('\n')

            # Find connector and extract EDID
            for i, line in enumerate(lines):
                if line.startswith(connector_name + ' '):
                    # Look for EDID in next lines
                    edid_hex = []
                    for j in range(i+1, min(i+30, len(lines))):
                        if lines[j].strip().startswith('EDID:'):
                            # Get hex data from next lines
                            for k in range(j+1, min(j+20, len(lines))):
                                hex_line = lines[k].strip()
                                if hex_line and all(c in '0123456789abcdef' for c in hex_line):
                                    edid_hex.append(hex_line)
                                elif not hex_line or hex_line[0] not in '\t ':
                                    break
                            break

                    if edid_hex:
                        # Parse EDID to get monitor name
                        edid_str = ''.join(edid_hex)

                        # Extract manufacturer ID (bytes 8-9) and product ID (bytes 10-11) for fallback
                        manufacturer = None
                        product_id = None

                        if len(edid_str) >= 22:  # Need at least 11 bytes (22 hex chars)
                            try:
                                # Manufacturer ID: bytes 8-9 (compressed 3-letter code)
                                mfg_bytes = bytes.fromhex(edid_str[16:20])  # bytes 8-9
                                mfg_word = (mfg_bytes[0] << 8) | mfg_bytes[1]
                                # Decode 5-bit compressed ASCII: bits 14-10, 9-5, 4-0
                                char1 = chr(((mfg_word >> 10) & 0x1F) + 64)
                                char2 = chr(((mfg_word >> 5) & 0x1F) + 64)
                                char3 = chr((mfg_word & 0x1F) + 64)
                                manufacturer = char1 + char2 + char3

                                # Product ID: bytes 10-11 (little-endian)
                                prod_bytes = bytes.fromhex(edid_str[20:24])  # bytes 10-11
                                product_id = (prod_bytes[1] << 8) | prod_bytes[0]
                            except:
                                pass

                        # Look for descriptor blocks (bytes 54-125) for monitor name
                        for block_start in range(54*2, 126*2, 18*2):  # 4 descriptor blocks
                            if block_start + 10 <= len(edid_str):
                                descriptor = edid_str[block_start:block_start+10]
                                if descriptor == '000000fc00':  # Monitor name descriptor
                                    # Next 13 bytes are ASCII name
                                    name_hex = edid_str[block_start+10:block_start+36]
                                    name_bytes = bytes.fromhex(name_hex)
                                    # Strip null bytes and whitespace, decode ASCII
                                    monitor_name = name_bytes.decode('ascii', errors='ignore').strip('\x00\n\r ')
                                    if monitor_name:
                                        return monitor_name

                        # Fallback: Use manufacturer + product ID if available
                        if manufacturer and product_id is not None:
                            return f"{manufacturer}{product_id:04X}"
                    break

            # Final fallback: use connector name
            return connector_name
        except Exception as e:
            return connector_name

    def get_monitor_info_full(self, connector_name):
        """Extract comprehensive monitor info from EDID and xrandr"""
        info = {
            'model': 'Unknown',
            'manufacturer': 'Unknown',
            'serial': 'Unknown',
            'resolution': 'Unknown',
            'refresh_rate': 'Unknown',
            'connector_type': 'Unknown',
            'physical_size': 'Unknown'
        }

        try:
            result = subprocess.run(['xrandr', '--props'],
                                  capture_output=True, text=True, timeout=5)
            lines = result.stdout.split('\n')

            # Find connector line
            for i, line in enumerate(lines):
                if line.startswith(connector_name + ' '):
                    # Extract resolution and refresh rate from connector line
                    # Format: "DisplayPort-0 connected primary 3200x1800+0+0 (normal...) 560mm x 315mm"
                    if ' connected' in line:
                        # Get resolution
                        res_match = re.search(r'(\d+)x(\d+)\+\d+\+\d+', line)
                        if res_match:
                            info['resolution'] = f"{res_match.group(1)}x{res_match.group(2)}"

                        # Get physical size
                        size_match = re.search(r'(\d+)mm x (\d+)mm', line)
                        if size_match:
                            width_mm = int(size_match.group(1))
                            height_mm = int(size_match.group(2))
                            width_in = round(width_mm / 25.4, 1)
                            height_in = round(height_mm / 25.4, 1)
                            diagonal_in = round(((width_mm/25.4)**2 + (height_mm/25.4)**2)**0.5, 1)
                            info['physical_size'] = f"{diagonal_in}\" ({width_mm}x{height_mm}mm)"

                    # Determine connector type from name
                    if 'DisplayPort' in connector_name:
                        info['connector_type'] = 'DisplayPort'
                    elif 'HDMI' in connector_name:
                        info['connector_type'] = 'HDMI'
                    elif 'DVI' in connector_name:
                        info['connector_type'] = 'DVI'
                    elif 'VGA' in connector_name:
                        info['connector_type'] = 'VGA'

                    # Look for current mode to get refresh rate
                    for j in range(i+1, min(i+50, len(lines))):
                        mode_line = lines[j]
                        # Current mode has * or *+ marker
                        if '*' in mode_line:
                            # Extract refresh rate - format: "   3200x1800     30.00*+"
                            # Try multiple patterns
                            rate_match = re.search(r'(\d+\.\d+)\*', mode_line)
                            if not rate_match:
                                rate_match = re.search(r'(\d+)\.\d+\*', mode_line)  # Alternative
                            if rate_match:
                                rate = rate_match.group(1)
                                # Check if it already has decimal
                                if '.' not in rate:
                                    rate = rate + ".00"
                                info['refresh_rate'] = f"{rate}Hz"
                                console_print(f"Found refresh rate: {info['refresh_rate']}")
                                break
                        # Stop at next connector
                        if mode_line and not mode_line[0].isspace() and mode_line[0].isalpha():
                            break

                    # Look for EDID to extract manufacturer, model, serial
                    edid_hex = []
                    for j in range(i+1, min(i+30, len(lines))):
                        if lines[j].strip().startswith('EDID:'):
                            for k in range(j+1, min(j+20, len(lines))):
                                hex_line = lines[k].strip()
                                if hex_line and all(c in '0123456789abcdef' for c in hex_line):
                                    edid_hex.append(hex_line)
                                elif not hex_line or hex_line[0] not in '\t ':
                                    break
                            break

                    if edid_hex:
                        edid_str = ''.join(edid_hex)

                        # Manufacturer ID (bytes 8-9)
                        if len(edid_str) >= 20:
                            mfg_bytes = edid_str[16:20]
                            mfg_int = int(mfg_bytes, 16)
                            # Decode manufacturer ID (3 x 5-bit characters)
                            char1 = chr(((mfg_int >> 10) & 0x1F) + 64)
                            char2 = chr(((mfg_int >> 5) & 0x1F) + 64)
                            char3 = chr((mfg_int & 0x1F) + 64)
                            info['manufacturer'] = f"{char1}{char2}{char3}"

                        # Extract monitor model and serial from descriptors
                        for block_start in range(54*2, 126*2, 18*2):
                            if block_start + 10 <= len(edid_str):
                                descriptor = edid_str[block_start:block_start+10]
                                # Monitor name (FC)
                                if descriptor == '000000fc00':
                                    name_hex = edid_str[block_start+10:block_start+36]
                                    name_bytes = bytes.fromhex(name_hex)
                                    model = name_bytes.decode('ascii', errors='ignore').strip('\x00\n\r ')
                                    if model:
                                        info['model'] = model
                                # Serial number (FF)
                                elif descriptor == '000000ff00':
                                    serial_hex = edid_str[block_start+10:block_start+36]
                                    serial_bytes = bytes.fromhex(serial_hex)
                                    serial = serial_bytes.decode('ascii', errors='ignore').strip('\x00\n\r ')
                                    if serial:
                                        info['serial'] = serial
                    break

            return info

        except Exception as e:
            console_print(f"Error extracting monitor info: {e}")
            return info

    def get_available_refresh_rates(self, connector_name):
        """Get available refresh rates for the current resolution"""
        try:
            result = subprocess.run(['xrandr'],
                                  capture_output=True, text=True, timeout=5)
            if result.returncode != 0:
                return []

            lines = result.stdout.split('\n')
            current_resolution = None
            available_rates = []
            current_rate = None

            # Find connector and its current resolution
            for i, line in enumerate(lines):
                if line.startswith(connector_name + ' '):
                    # Extract current resolution from connector line
                    # Format: "DisplayPort-0 connected primary 3200x1800+0+0 ..."
                    res_match = re.search(r'(\d+)x(\d+)\+\d+\+\d+', line)
                    if res_match:
                        current_resolution = f"{res_match.group(1)}x{res_match.group(2)}"
                        console_print(f"Current resolution for {connector_name}: {current_resolution}")

                    # Now find all modes for this resolution
                    if current_resolution:
                        for j in range(i+1, min(i+100, len(lines))):
                            mode_line = lines[j]
                            # Stop at next connector
                            if mode_line and not mode_line[0].isspace() and mode_line[0].isalpha():
                                break

                            # Check if this mode line matches current resolution
                            if current_resolution in mode_line:
                                # Extract all refresh rates from this line
                                # Format: "   3200x1800     30.00*+  60.00    50.00"
                                # * means current, + means preferred
                                rate_matches = re.findall(r'(\d+\.\d+)(\*|\+|\s)', mode_line)
                                for rate, marker in rate_matches:
                                    rate_float = float(rate)
                                    rate_str = f"{rate_float:.2f}Hz"
                                    if rate_str not in available_rates:
                                        available_rates.append(rate_str)
                                    # Track current rate
                                    if '*' in marker:
                                        current_rate = rate_str
                    break

            # Sort rates numerically
            if available_rates:
                rates_sorted = sorted(available_rates, key=lambda x: float(x.replace('Hz', '')), reverse=True)
                console_print(f"Available refresh rates: {rates_sorted}, Current: {current_rate}")
                return rates_sorted, current_rate

            return [], None

        except Exception as e:
            console_print(f"Error getting refresh rates: {e}")
            return [], None

    def get_available_resolutions(self, connector_name):
        """Get available resolutions for the connector"""
        try:
            result = subprocess.run(['xrandr'],
                                  capture_output=True, text=True, timeout=5)
            if result.returncode != 0:
                return [], None

            lines = result.stdout.split('\n')
            available_resolutions = []
            current_resolution = None

            # Find connector and collect all resolutions
            for i, line in enumerate(lines):
                if line.startswith(connector_name + ' '):
                    # Extract current resolution from connector line
                    res_match = re.search(r'(\d+)x(\d+)\+\d+\+\d+', line)
                    if res_match:
                        current_resolution = f"{res_match.group(1)}x{res_match.group(2)}"
                        console_print(f"Current resolution for {connector_name}: {current_resolution}")

                    # Collect all available resolutions from mode lines
                    for j in range(i+1, min(i+100, len(lines))):
                        mode_line = lines[j]
                        # Stop at next connector
                        if mode_line and not mode_line[0].isspace() and mode_line[0].isalpha():
                            break

                        # Extract resolution from mode line
                        # Format: "   3200x1800     30.00*+  60.00"
                        res_match = re.match(r'\s+(\d+)x(\d+)\s+', mode_line)
                        if res_match:
                            resolution = f"{res_match.group(1)}x{res_match.group(2)}"
                            if resolution not in available_resolutions:
                                available_resolutions.append(resolution)
                    break

            # Sort resolutions by total pixels (descending)
            if available_resolutions:
                def resolution_pixels(res_str):
                    w, h = res_str.split('x')
                    return int(w) * int(h)

                resolutions_sorted = sorted(available_resolutions,
                                          key=resolution_pixels,
                                          reverse=True)
                console_print(f"Available resolutions: {resolutions_sorted}, Current: {current_resolution}")
                return resolutions_sorted, current_resolution

            return [], None

        except Exception as e:
            console_print(f"Error getting resolutions: {e}")
            return [], None

    def load_settings(self):
        """Load saved settings from file"""
        try:
            if self.settings_file.exists():
                with open(self.settings_file, 'r') as f:
                    return json.load(f)
            return {}
        except:
            return {}

    def save_settings(self, settings):
        """Save settings to file"""
        try:
            with open(self.settings_file, 'w') as f:
                json.dump(settings, f, indent=2)
        except Exception as e:
            console_print(f"Error saving settings: {e}")

    def check_umr_status(self):
        """Check if UMR is installed and get version"""
        import shutil

        # Method 1: Check if umr is in PATH
        umr_path = shutil.which('umr')
        if not umr_path:
            return False, None

        # Method 2: Try to get version
        try:
            result = subprocess.run(['umr', '--version'],
                                  capture_output=True,
                                  text=True,
                                  timeout=2)
            if result.returncode == 0:
                version = result.stdout.strip()
                return True, version
            return True, "Unknown"
        except Exception:
            return False, None

    def check_umr_on_startup(self):
        """Check if UMR is installed on startup and show warning if not"""
        umr_status, _ = self.check_umr_status()

        if not umr_status:
            # Show warning popup
            self.show_umr_warning_popup()

    def show_umr_warning_popup(self):
        """Show warning popup that UMR is not detected"""
        umr_status, _ = self.check_umr_status()

        if umr_status:
            messagebox.showinfo("UMR Detected",
                              "✓ UMR is installed and working!\n\n"
                              "All dithering controls are available.")
            return

        self.show_umr_not_detected_dialog()

