    def toggle_setting(self, idx, bitfield, value):
        """Toggle setting with debug logging"""
        path = f"{self.asic_name}.{self.block_name}.mmFMT{idx}_FMT_BIT_DEPTH_CONTROL"
        val = 1 if value else 0

        # Get connector name for logging
        connector_name = self.monitor_connector_names.get(idx, f"FMT{idx}")
        # For logging: show the target state as after_str
        before_str = 'ON' if not value else 'OFF'
        after_str = 'ON' if value else 'OFF'

        # Run command
        self.run_umr_command(["-i", str(self.gpu_instance), "-wb", f"{path}.{bitfield}", str(val)])
        self.status_var.set(f"Set {bitfield} = {val}")

        # Log to debug console
        command = f"umr -wb {path}.{bitfield} {val}"
        # Use UI-friendly names so the log stays readable (no trailing 'En/Enable')
        pretty = {
            'FMT_SPATIAL_DITHER_EN': 'Spatial Dither',
            'FMT_TEMPORAL_DITHER_EN': 'Temporal Dither',
            'FMT_RGB_RANDOM_ENABLE': 'RGB Noise',
            'FMT_HIGHPASS_RANDOM_ENABLE': 'Highpass Random Filter',
            'FMT_FRAME_RANDOM_ENABLE': 'Frame Random',
            'FMT_TRUNCATE_EN': 'Truncate',
        }
        setting_name = pretty.get(bitfield)
        if not setting_name:
            # Fallback: remove common suffixes and prettify
            base = bitfield.replace('FMT_', '')
            base = re.sub(r'_(EN|ENABLE)$', '', base)
            base = base.replace('_', ' ')
            setting_name = base.title()

        self.log_command(f"{connector_name}: {setting_name}", before_str, command, after_str, success=True)

        # Auto-save settings for this monitor
        self.auto_save_current_monitor(idx)

    def set_truncate_depth(self, idx, depth_str=None):
        """Set truncate bit depth with debug logging"""
        if depth_str is None:
            var = self.truncate_depth_vars.get(idx)
            depth_str = var.get() if var else '8-bit'

        depth_val = self.TRUNCATE_DEPTH_REVERSE.get(depth_str, 1)
        path = f"{self.asic_name}.{self.block_name}.mmFMT{idx}_FMT_BIT_DEPTH_CONTROL"

        # Get current value for logging
        connector_name = self.monitor_connector_names.get(idx, f"FMT{idx}")
        before_str = self.truncate_depth_vars.get(idx)
        before_value = before_str.get() if before_str else "Unknown"

        # Run command
        self.run_umr_command(["-i", str(self.gpu_instance), "-wb", f"{path}.FMT_TRUNCATE_DEPTH", str(depth_val)])
        self.status_var.set(f"Set truncate depth to {depth_str}")

        # Log to debug console
        command = f"umr -wb {path}.FMT_TRUNCATE_DEPTH {depth_val}"
        self.log_command(f"{connector_name}: Truncate Depth", before_value, command, depth_str, success=True)

        self.auto_save_current_monitor(idx)

